from prometheus_client import start_http_server, Counter
from flask import Flask, request

app = Flask(__name__)

# Counter to track HTTP requests with labels for user_id, session_id, and full request path
http_requests_counter = Counter(
    'http_requests_total',
    'Total HTTP Requests',
    ['user_id', 'session_id', 'request_path']
)

@app.route('/<path:path>', methods=['GET', 'POST', 'PUT', 'DELETE'])
def track_request(path):
    user_id = request.args.get('user_id', 'unknown')
    session_id = request.args.get('session_id', 'unknown')
    request_path = request.path

    # Increment the counter for the specific user-path combination
    http_requests_counter.labels(user_id=user_id, session_id=session_id, request_path=request_path).inc()

    return f"Tracked request for user_id: {user_id}, session_id: {session_id}, path: {request_path}"

if __name__ == '__main__':
    # Start Prometheus metrics server
    start_http_server(8000)
    # Start Flask application
    app.run(host='0.0.0.0', port=5000)